import React, { useState } from "react";

function Shop() {
  // Predefined 16 products
  const [products] = useState([
    { id: 1, name: "Smartphone", price: 499, image: "https://via.placeholder.com/150" },
    { id: 2, name: "Laptop", price: 899, image: "https://via.placeholder.com/150" },
    { id: 3, name: "Headphones", price: 99, image: "https://via.placeholder.com/150" },
    { id: 4, name: "Smartwatch", price: 199, image: "https://via.placeholder.com/150" },
    { id: 5, name: "Tablet", price: 299, image: "https://via.placeholder.com/150" },
    { id: 6, name: "Camera", price: 599, image: "https://via.placeholder.com/150" },
    { id: 7, name: "Keyboard", price: 49, image: "https://via.placeholder.com/150" },
    { id: 8, name: "Mouse", price: 29, image: "https://via.placeholder.com/150" },
    { id: 9, name: "Speaker", price: 79, image: "https://via.placeholder.com/150" },
    { id: 10, name: "Monitor", price: 249, image: "https://via.placeholder.com/150" },
    { id: 11, name: "Printer", price: 149, image: "https://via.placeholder.com/150" },
    { id: 12, name: "Router", price: 89, image: "https://via.placeholder.com/150" },
    { id: 13, name: "External HDD", price: 129, image: "https://via.placeholder.com/150" },
    { id: 14, name: "USB Drive", price: 19, image: "https://via.placeholder.com/150" },
    { id: 15, name: "Charger", price: 39, image: "https://via.placeholder.com/150" },
    { id: 16, name: "Power Bank", price: 59, image: "https://via.placeholder.com/150" },
  ]);

  return (
    <div className="shop-container">
      <h2>All Products</h2>
      <div
        className="products-grid"
        style={{ display: "flex", flexWrap: "wrap", gap: "20px" }}
      >
        {products.map((product) => (
          <div
            key={product.id}
            className="product-card"
            style={{
              border: "1px solid #ccc",
              borderRadius: "8px",
              padding: "10px",
              width: "200px",
              textAlign: "center",
            }}
          >
            <img
              src={product.image}
              alt={product.name}
              style={{ width: "100%", marginBottom: "10px" }}
            />
            <h3>{product.name}</h3>
            <p>${product.price.toFixed(2)}</p>
          </div>
        ))}
      </div>
    </div>
  );
}

export default Shop;
